={{
  JSON.stringify(
    (() => {
      // 1) Answer text from LLM step
      const answer = $('Generate response').first().json.text;
      const intentType = $('downstream node').first().json?.intent || 'datasheet';

      // 2) Requested gases from downstream node (e.g. ['Oxygen','Nitrogen'])
      const gasesNorm = $('downstream node').first().json?.gasesNorm || [];

      // 3) Build a lookup set of all identifiers for each requested gas.
      //    This covers both short symbols (O2, N2) and full names (Oxygen, Nitrogen)
      //    so we can match against any filename / doc_id pattern.
      const GAS_ALIASES = {
        Oxygen:         ['oxygen', 'o2'],
        Nitrogen:       ['nitrogen', 'n2'],
        Hydrogen:       ['hydrogen', 'h2'],
        'Carbon Dioxide': ['carbon_dioxide', 'carbon dioxide', 'co2'],
        Argon:          ['argon', 'ar'],
        Helium:         ['helium', 'he'],
        Methane:        ['methane', 'ch4'],
      };

      // Build a flat set of lowercase tokens for all requested gases
      const requestedTokens = new Set();
      for (const gasName of gasesNorm) {
        requestedTokens.add(gasName.toLowerCase());
        const aliases = GAS_ALIASES[gasName] || [];
        aliases.forEach(a => requestedTokens.add(a.toLowerCase()));
      }

      // Helper: does a given string (filename/doc_id) match one of the requested gases?
      function matchesRequestedGas(str) {
        if (!str) return false;
        const lower = str.toLowerCase();
        for (const token of requestedTokens) {
          // Use word-boundary-style check: token must be a standalone segment
          // e.g. 'o2' matches 'product_data_sheet_o2.pdf' but not inside 'co2'
          // We use a regex with non-alphanumeric delimiters or string boundaries
          const escaped = token.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          const re = new RegExp('(^|[^a-z0-9])' + escaped + '($|[^a-z0-9])', 'i');
          if (re.test(lower)) return true;
        }
        return false;
      }

      // 4) Collect all unique documents from Pinecone chunks
      const allChunks = $('Get top chunks matching query').all();
      const seenFiles = new Set();
      const candidates = [];

      for (const item of allChunks) {
        const meta = item.json?.document?.metadata ?? {};
        const fileName = meta.file_name || '';
        if (!fileName) continue;
        if (seenFiles.has(fileName)) continue;
        seenFiles.add(fileName);

        const docId = fileName.replace(/\.(pdf|txt|docx?)$/i, '') || meta.doc_id || '';
        const fileUrl =
          meta.file_url ||
          meta.source?.file_url ||
          meta.webContentLink ||
          meta.webViewLink ||
          (meta.file_id ? `https://drive.google.com/uc?id=${meta.file_id}&export=download` : '') ||
          (meta.id      ? `https://drive.google.com/uc?id=${meta.id}&export=download`      : '') ||
          '';
        candidates.push({ doc_id: docId, title: fileName, file_url: fileUrl, type: intentType, meta });
      }

      // 5) Filter: keep only files that match one of the explicitly requested gases.
      //    If no gasesNorm were extracted (e.g. general datasheet query), keep all.
      let sources;
      if (gasesNorm.length === 0) {
        // No specific gases requested — return all found (general query)
        sources = candidates.map(({ meta: _m, ...rest }) => rest);
      } else {
        sources = candidates
          .filter(c => {
            // Check doc_id, title, and any metadata product field
            return matchesRequestedGas(c.doc_id) ||
                   matchesRequestedGas(c.title) ||
                   matchesRequestedGas(c.meta?.product) ||
                   matchesRequestedGas(c.meta?.gas_name);
          })
          .map(({ meta: _m, ...rest }) => rest);
      }

      // 6) Do not return source chips if LLM said it couldn't find the data
      const NOT_FOUND_PHRASES = ["couldn't find","could not find","not found","no information","i don't have","unable to find","not present in","not available in","doesn't contain","does not contain","cannot find","not in the provided","not mentioned","not specified"];
      const dataNotFound = NOT_FOUND_PHRASES.some(p => answer.toLowerCase().includes(p));

      return {
        response_message: answer,
        sources: dataNotFound ? [] : sources,
        meta: {
          confidence: $('downstream node').first().json?.confidence ?? null,
          sources_used: dataNotFound ? 0 : sources.length
        }
      };
    })()
  )
}}

