// ── Gas alias map ──────────────────────────────────────────────────────
const GAS_ALIASES = {
  'oxygen':         ['O2','Oxygen'],
  'o2':             ['O2','Oxygen'],
  'nitrogen':       ['N2','Nitrogen'],
  'n2':             ['N2','Nitrogen'],
  'argon':          ['Ar','Argon'],
  'ar':             ['Ar','Argon'],
  'hydrogen':       ['H2','Hydrogen'],
  'h2':             ['H2','Hydrogen'],
  'carbon dioxide': ['CO2'],
  'co2':            ['CO2'],
  'helium':         ['He','Helium'],
  'he':             ['He','Helium'],
  'methane':        ['CH4','Methane'],
  'ch4':            ['CH4','Methane'],
};

function getGasTerms(gasName) {
  if (!gasName) return [];
  const key = gasName.toLowerCase().trim();
  return GAS_ALIASES[key] || [gasName];
}

function fileNameMatchesTerms(fileName, terms) {
  if (!terms || terms.length === 0) return true;
  const up = fileName.toUpperCase();
  return terms.some(function(raw) {
    const t = raw.toUpperCase();
    return up.indexOf('_' + t + '_') !== -1
        || up.indexOf('_' + t + '.') !== -1
        || up.indexOf('-' + t + '-') !== -1
        || up.indexOf('-' + t + '.') !== -1
        || up.startsWith(t + '_') || up.startsWith(t + '-')
        || up.endsWith('_' + t)   || up.endsWith('-' + t);
  });
}

// ── Intent-Product Mapping: which gases are requested for DATASHEET ──────
const intentProductMap = $('downstream node').first().json.intentProductMap || {};
const gasesNorm = $('downstream node').first().json.gasesNorm || [];
const singleGas = $('downstream node').first().json.entities?.gas || '';

// Use per-intent mapping if available; otherwise fall back to all gases
const dsGases = (intentProductMap.datasheet && intentProductMap.datasheet.length > 0)
  ? intentProductMap.datasheet
  : gasesNorm;

// Build gas terms ONLY for the gases that belong to the datasheet intent
const dsGasTerms = dsGases.length > 0
  ? dsGases.flatMap(g => getGasTerms(g))
  : getGasTerms(singleGas);

// ── Extract unique DS sources from Pinecone chunks ────────────────────
const chunks = $input.all();
const seen = {};
const dsSources = [];

for (const chunk of chunks) {
  const meta = chunk.json?.document?.metadata ?? {};
  const fileName = meta.file_name || '';
  const dedupeKey = fileName || meta.doc_id || meta.source || '';
  if (!dedupeKey) continue;
  // Skip if file doesn't match the DATASHEET-specific gases
  if (dsGasTerms.length > 0 && !fileNameMatchesTerms(fileName, dsGasTerms)) continue;
  if (!seen[dedupeKey]) {
    seen[dedupeKey] = true;
    const fileUrl =
      meta.file_url ||
      meta.webContentLink ||
      meta.webViewLink ||
      (meta.file_id ? 'https://drive.google.com/uc?id=' + meta.file_id + '&export=download' : '') ||
      (meta.id      ? 'https://drive.google.com/uc?id=' + meta.id      + '&export=download' : '') ||
      '';
    const docId = fileName.replace(/\.(pdf|txt|docx?)$/i, '') || meta.doc_id || fileName || '';
    dsSources.push({ doc_id: docId, title: fileName || docId, file_url: fileUrl, type: 'datasheet' });
  }
}

// Pass through for Build Multi Response
return {
  dsSources: dsSources,
  dsGases: dsGases,
  dsGasTerms: dsGasTerms,
  intentProductMap: intentProductMap,
  gasesNorm: gasesNorm,
  singleGas: singleGas
};

// ── Re-use context from Extract DS Sources + downstream node ────────────
const dsResult         = $('Extract DS Sources').first().json;
const dsSources        = dsResult.dsSources        || [];
const intentProductMap = dsResult.intentProductMap  || ($('downstream node').first().json.intentProductMap || {});
const gasesNorm        = dsResult.gasesNorm         || ($('downstream node').first().json.gasesNorm || []);
const singleGas        = dsResult.singleGas         || $('downstream node').first().json.entities?.gas || '';

// ── Gas alias map ─────────────────────────────────────────────────────────
const GAS_ALIASES = {
  'oxygen':         ['O2','Oxygen'],
  'o2':             ['O2','Oxygen'],
  'nitrogen':       ['N2','Nitrogen'],
  'n2':             ['N2','Nitrogen'],
  'argon':          ['Ar','Argon'],
  'ar':             ['Ar','Argon'],
  'hydrogen':       ['H2','Hydrogen'],
  'h2':             ['H2','Hydrogen'],
  'carbon dioxide': ['CO2'],
  'co2':            ['CO2'],
  'helium':         ['He','Helium'],
  'he':             ['He','Helium'],
  'methane':        ['CH4','Methane'],
  'ch4':            ['CH4','Methane'],
};

function getGasTerms(gasName) {
  if (!gasName) return [];
  const key = gasName.toLowerCase().trim();
  return GAS_ALIASES[key] || [gasName];
}

function fileNameMatchesTerms(fileName, terms) {
  if (!terms || terms.length === 0) return true;
  const up = fileName.toUpperCase();
  return terms.some(function(raw) {
    const t = raw.toUpperCase();
    return up.indexOf('_' + t + '_') !== -1
        || up.indexOf('_' + t + '.') !== -1
        || up.indexOf('-' + t + '-') !== -1
        || up.indexOf('-' + t + '.') !== -1
        || up.startsWith(t + '_') || up.startsWith(t + '-')
        || up.endsWith('_' + t)   || up.endsWith('-' + t);
  });
}

// ── Determine which gases belong to QUOTATION intent ─────────────────────
// Use per-intent mapping if available; fallback to all gases
const qtGases = (intentProductMap.quotation && intentProductMap.quotation.length > 0)
  ? intentProductMap.quotation
  : gasesNorm;

const qtGasTerms = qtGases.length > 0
  ? qtGases.flatMap(g => getGasTerms(g))
  : getGasTerms(singleGas);

// ── Extract ALL unique QT sources from Pinecone chunks ────────────────────
const qtChunksAll = $input.all();
const seenQt = {};
const qtSourcesRaw = [];

for (const chunk of qtChunksAll) {
  const meta = chunk.json?.document?.metadata ?? {};
  const fileName = meta.file_name || '';
  const dedupeKey = fileName || meta.doc_id || meta.source || '';
  if (!dedupeKey) continue;
  if (!seenQt[dedupeKey]) {
    seenQt[dedupeKey] = true;
    const fileUrl =
      meta.file_url ||
      meta.webContentLink ||
      meta.webViewLink ||
      (meta.file_id ? 'https://drive.google.com/uc?id=' + meta.file_id + '&export=download' : '') ||
      (meta.id      ? 'https://drive.google.com/uc?id=' + meta.id      + '&export=download' : '') ||
      '';
    const docId = fileName.replace(/\.(pdf|txt|docx?)$/i, '') || meta.doc_id || fileName || '';
    qtSourcesRaw.push({ doc_id: docId, title: fileName || docId, file_url: fileUrl, type: 'quotation' });
  }
}

// ── Filter QT sources: keep only files matching QUOTATION-specific gases ──
const qtSources = qtGasTerms.length > 0
  ? qtSourcesRaw.filter(s => fileNameMatchesTerms(s.title, qtGasTerms))
  : qtSourcesRaw;

// ── Intent metadata ───────────────────────────────────────────────────────
const intentsList = $('downstream node').first().json.intents || [];
const confidence  = $('downstream node').first().json.confidence ?? null;

// ── Merge all sources: datasheets first, then quotations ──────────────────
const allSources = [...dsSources, ...qtSources];

// ── Build readable response message with PER-INTENT gas labels ────────────
const dsGasesForLabel = (intentProductMap.datasheet && intentProductMap.datasheet.length > 0)
  ? intentProductMap.datasheet
  : gasesNorm;
const dsLabel = dsGasesForLabel.length > 0 ? dsGasesForLabel.join(' and ') : '';
const qtLabel = qtGases.length > 0 ? qtGases.join(' and ') : '';

const parts = [];
if (dsSources.length > 0) {
  const forDs = dsLabel ? ' for ' + dsLabel : '';
  parts.push('Product data sheet' + (dsSources.length > 1 ? 's' : '') + forDs + ': ' +
    dsSources.map(function(s) { return s.title; }).join(', ') + '.');
} else {
  parts.push('No product data sheet was found for this query.');
}
if (qtSources.length > 0) {
  const forQt = qtLabel ? ' for ' + qtLabel : '';
  parts.push('Quotation document' + (qtSources.length > 1 ? 's' : '') + forQt + ': ' +
    qtSources.map(function(s) { return s.title; }).join(', ') + '.');
} else {
  parts.push('No quotation document was found for this query.');
}

const responseMessage = (allSources.length > 0
  ? 'Here are the requested documents. '
  : 'I was unable to find the requested documents. ')
  + parts.join(' ');

return {
  result: {
    response_message: responseMessage,
    sources: allSources,
    meta: {
      confidence: confidence,
      sources_used: allSources.length,
      intents: intentsList
    }
  }
};

