// Split files array into individual items for Google Drive download
const input = $input.first();
const files = input.json.files || [];
if (!files.length) throw new Error('No files to download for email.');

return files.map(function(f, i) {
  return {
    json: {
      file_url: f.file_url || '',
      filename: f.filename || f.title || 'Document_' + (i + 1),
      index: i
    }
  };
});

// Build raw MIME email with HTML body + all binary attachments
const emailData = $('Build Multi File Email').first().json;
const toEmail = emailData.email;
const subject = emailData.subject;
const html = emailData.html;
const fileCount = emailData.fileCount;
const originalFiles = emailData.files || [];

const items = $input.all();
if (!items.length) throw new Error('No downloaded files for email attachments.');

const boundary = 'linde_' + Date.now() + '_' + Math.random().toString(36).substr(2, 8);
const parts = [];

// RFC 2822 headers
parts.push('MIME-Version: 1.0');
parts.push('To: ' + toEmail);
parts.push('Subject: =?UTF-8?B?' + Buffer.from(subject).toString('base64') + '?=');
parts.push('Content-Type: multipart/mixed; boundary="' + boundary + '"');
parts.push('');

// Part 1: HTML body
parts.push('--' + boundary);
parts.push('Content-Type: text/html; charset="UTF-8"');
parts.push('Content-Transfer-Encoding: base64');
parts.push('');
parts.push(Buffer.from(html).toString('base64'));

// Parts 2..N: file attachments
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.binary || !item.binary.data) continue;
  const bin = item.binary.data;
  const fname = bin.fileName || originalFiles[i]?.filename || ('document_' + (i + 1) + '.pdf');
  const mtype = bin.mimeType || 'application/pdf';

  parts.push('--' + boundary);
  parts.push('Content-Type: ' + mtype + '; name="' + fname + '"');
  parts.push('Content-Disposition: attachment; filename="' + fname + '"');
  parts.push('Content-Transfer-Encoding: base64');
  parts.push('');
  parts.push(bin.data);
}

parts.push('--' + boundary + '--');

// Base64url-encode for Gmail API
const raw = Buffer.from(parts.join('\r\n'))
  .toString('base64')
  .replace(/\+/g, '-')
  .replace(/\//g, '_')
  .replace(/=+$/g, '');

return [{ json: { raw, email: toEmail, fileCount } }];
